using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model before configuring DI
var trainer = new TicketModelTrainer(
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<TicketModelTrainer>());
trainer.TrainAndEvaluate();

// Share label names so the controller can map score arrays to categories
builder.Services.AddSingleton(new LabelMetadata(trainer.Labels));

// Register pooled prediction engine (thread-safe) from the saved model
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

/// <summary>Holds the ordered label names extracted from the trained model.</summary>
public record LabelMetadata(string[] Labels);

